mapper.select:
select
id,
code,
name,
status,
built_in as builtIn,
subject_type_id as subjectTypeCode,
realm_id as realmId,
parent_id as parentId,
create_time as createTime
from subject


        and subject_type_id = #{request.subjectTypeId}


        and realm_id = #{request.realmId}


        and `code` = #{request.code}


        and `name` like concat('%', #{request.name}, '%')


        and root_subject_id = #{request.rootSubjectId}


        and parent_id = #{request.parentSubjectId}


        and is_root = #{request.isRoot}


        and `status` = #{request.status}


order by create_time desc
